const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const { promisify } = require('util');
const stream = require('stream');
const pipeline = promisify(stream.pipeline);

const UPLOAD_DIR = path.join(__dirname, 'uploads');
const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB
const ALLOWED_MIME_TYPES = [
  'image/jpeg',
  'image/png',
  'image/gif',
  'image/webp',
  'application/pdf',
  'text/plain'
];
const ALLOWED_EXTENSIONS = ['.jpg', '.jpeg', '.png', '.gif', '.webp', '.pdf', '.txt'];

function sanitizeFilename(filename) {
  const ext = path.extname(filename).toLowerCase();
  const basename = path.basename(filename, ext);
  const sanitized = basename.replace(/[^a-zA-Z0-9_-]/g, '_').substring(0, 100);
  return sanitized + ext;
}

function generateUniqueFilename(originalFilename) {
  const ext = path.extname(originalFilename).toLowerCase();
  const timestamp = Date.now();
  const randomBytes = crypto.randomBytes(8).toString('hex');
  return `${timestamp}_${randomBytes}${ext}`;
}

function validateFileExtension(filename) {
  const ext = path.extname(filename).toLowerCase();
  return ALLOWED_EXTENSIONS.includes(ext);
}

function validateMimeType(mimetype) {
  return ALLOWED_MIME_TYPES.includes(mimetype);
}

async function ensureUploadDirectory() {
  try {
    await fs.promises.access(UPLOAD_DIR);
  } catch {
    await fs.promises.mkdir(UPLOAD_DIR, { recursive: true, mode: 0o755 });
  }
}

async function handleFileUpload(file) {
  if (!file) {
    throw new Error('No file provided');
  }

  if (!file.originalname || !file.mimetype) {
    throw new Error('Invalid file object');
  }

  if (!validateMimeType(file.mimetype)) {
    throw new Error('File type not allowed');
  }

  if (!validateFileExtension(file.originalname)) {
    throw new Error('File extension not allowed');
  }

  if (file.size > MAX_FILE_SIZE) {
    throw new Error(`File size exceeds maximum allowed size of ${MAX_FILE_SIZE} bytes`);
  }

  await ensureUploadDirectory();

  const sanitizedOriginalName = sanitizeFilename(file.originalname);
  const uniqueFilename = generateUniqueFilename(sanitizedOriginalName);
  const filepath = path.join(UPLOAD_DIR, uniqueFilename);

  const resolvedPath = path.resolve(filepath);
  const resolvedUploadDir = path.resolve(UPLOAD_DIR);
  if (!resolvedPath.startsWith(resolvedUploadDir)) {
    throw new Error('Invalid file path');
  }

  if (file.buffer) {
    await fs.promises.writeFile(filepath, file.buffer, { mode: 0o644 });
  } else if (file.path) {
    await fs.promises.copyFile(file.path, filepath);
    await fs.promises.chmod(filepath, 0o644);
    try {
      await fs.promises.unlink(file.path);
    } catch (err) {
      console.error('Failed to delete temporary file:', err);
    }
  } else if (file.stream) {
    const writeStream = fs.createWriteStream(filepath, { mode: 0o644 });
    await pipeline(file.stream, writeStream);
  } else {
    throw new Error('Unsupported file format');
  }

  return {
    success: true,
    filename: uniqueFilename,
    originalname: sanitizedOriginalName,
    path: filepath,
    size: file.size,
    mimetype: file.mimetype
  };
}

async function handleMultipleFileUploads(files) {
  if (!Array.isArray(files) || files.length === 0) {
    throw new Error('No files provided');
  }

  const results = [];
  const errors = [];

  for (let i = 0; i < files.length; i++) {
    try {
      const result = await handleFileUpload(files[i]);
      results.push(result);
    } catch (error) {
      errors.push({
        index: i,
        filename: files[i].originalname,
        error: error.message
      });
    }
  }

  return {
    success: errors.length === 0,
    uploaded: results,
    errors: errors,
    total: files.length,
    successful: results.length,
    failed: errors.length
  };
}

module.exports = {
  handleFileUpload,
  handleMultipleFileUploads,
  UPLOAD_DIR,
  MAX_FILE_SIZE,
  ALLOWED_MIME_TYPES,
  ALLOWED_EXTENSIONS
};